// Composite transitions — pre-combining duration + easing
const PRIMER_TRANSITIONS = [
  { name: 'motion.transition.hover',       duration: 100, easingName: 'motion.easing.hover',  easing: [0.25, 0.1, 0.25, 1] },
  { name: 'motion.transition.stateChange', duration: 200, easingName: 'motion.easing.move',   easing: [0.6, 0, 0.2, 1] },
  { name: 'motion.transition.enter',       duration: 300, easingName: 'motion.easing.enter',  easing: [0.3, 0.8, 0.6, 1] },
  { name: 'motion.transition.exit',        duration: 200, easingName: 'motion.easing.exit',   easing: [0.7, 0.1, 0.75, 0.9] },
];

function cb([x1, y1, x2, y2]) {
  return `cubic-bezier(${x1}, ${y1}, ${x2}, ${y2})`;
}

function easingSVG([x1, y1, x2, y2], color = '#0969da') {
  const pts = [];
  for (let i = 0; i <= 20; i++) {
    const t = i / 20;
    const bx = 3*(1-t)*(1-t)*t*x1 + 3*(1-t)*t*t*x2 + t*t*t;
    const by = 3*(1-t)*(1-t)*t*y1 + 3*(1-t)*t*t*y2 + t*t*t;
    pts.push([bx * 40, (1 - by) * 8]);
  }
  const d = pts.map(([x, y], i) => `${i === 0 ? 'M' : 'L'}${x.toFixed(1)} ${y.toFixed(1)}`).join(' ');
  return `<svg width="40" height="8" viewBox="0 0 40 8" style="overflow:visible;display:inline-block;vertical-align:middle">
    <path d="${d}" fill="none" stroke="${color}" stroke-width="1.5"/>
  </svg>`;
}

